import { Component, OnInit } from '@angular/core';
import { ContenidoService } from '../../shared/services/contenido.service';

@Component({
  selector: 'app-inicio',
  templateUrl: './inicio.component.html'
})
export class InicioComponent implements OnInit {
  contenido: any = {
    hero: {
      titulo: '',
      subtitulo: '',
      descripcion: '',
      cta_texto: '',
      cta_link: '',
      imagen: ''
    },
    servicios_destacados: [],
    estadisticas: {
      clientes_satisfechos: '',
      proyectos_completados: '',
      años_experiencia: '',
      equipo_profesional: ''
    }
  };

  constructor(private contenidoService: ContenidoService) {}

  ngOnInit(): void {
    this.loadContent();
  }

  private loadContent(): void {
    this.contenidoService.getContenido().subscribe({
      next: (data) => {
        if (data && data.inicio) {
          this.contenido = data.inicio;
        }
      },
      error: (error) => {
        console.error('Error loading content:', error);
      }
    });
  }
}
<!-- Sección Hero: Área principal de bienvenida con título, descripción y CTA -->
<section class="container mx-auto px-4 flex flex-col lg:flex-row items-center justify-between min-h-screen py-12 lg:py-24 gap-8 lg:gap-16">
  <!-- Contenido textual del hero (lado izquierdo en desktop) -->
  <div class="flex-1 max-w-2xl text-center lg:text-left">
    <!-- Título principal con gradiente azul a verde -->
    <h1 class="text-4xl lg:text-6xl font-extrabold leading-tight mb-6 bg-gradient-to-r from-blue-600 to-green-400 bg-clip-text text-transparent">
      {{contenido.hero.titulo}}
    </h1>
    <!-- Subtítulo descriptivo -->
    <h2 class="text-xl lg:text-2xl font-medium text-gray-700 mb-6">{{contenido.hero.subtitulo}}</h2>
    <!-- Descripción detallada de los servicios -->
    <p class="text-lg text-gray-600 mb-8 leading-relaxed">{{contenido.hero.descripcion}}</p>

<!-- Services Section -->
<section class="bg-gray-50 py-16 lg:py-24">
  <div class="container mx-auto px-4">
    <h2 class="section-title">Nuestros Servicios</h2>
    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
      <div class="card" *ngFor="let servicio of contenido.servicios_destacados">
        <i [class]="servicio.icono" class="text-4xl text-blue-600 mb-6 block"></i>
        <h3 class="text-2xl font-semibold mb-4 text-gray-800">{{servicio.titulo}}</h3>
        <p class="text-gray-600 mb-6 leading-relaxed">{{servicio.descripcion}}</p>
        <a [routerLink]="[servicio.link]" class="text-blue-600 font-medium hover:text-blue-800 transition-colors">
          Saber más →
        </a>
      </div>
    </div>
  </div>
</section>

<!-- Stats Section -->
<section class="py-16 lg:py-24 bg-white">
  <div class="container mx-auto px-4">
    <div class="grid grid-cols-2 lg:grid-cols-4 gap-8">
      <div class="text-center">
        <h3 class="text-3xl lg:text-4xl font-bold text-blue-600 mb-2">{{contenido.estadisticas.clientes_satisfechos}}</h3>
        <p class="text-gray-600 text-sm lg:text-lg">Clientes Satisfechos</p>
      </div>
      <div class="text-center">
        <h3 class="text-3xl lg:text-4xl font-bold text-blue-600 mb-2">{{contenido.estadisticas.proyectos_completados}}</h3>
        <p class="text-gray-600 text-sm lg:text-lg">Proyectos Completados</p>
      </div>
      <div class="text-center">
        <h3 class="text-3xl lg:text-4xl font-bold text-blue-600 mb-2">{{contenido.estadisticas['años_experiencia']}}</h3>
        <p class="text-gray-600 text-sm lg:text-lg">Años de Experiencia</p>
      </div>
      <div class="text-center">
        <h3 class="text-3xl lg:text-4xl font-bold text-blue-600 mb-2">{{contenido.estadisticas.equipo_profesional}}</h3>
        <p class="text-gray-600 text-sm lg:text-lg">Profesionales</p>
      </div>
    </div>
  </div>
</section>

<!-- CTA Section -->
<section class="bg-gradient-to-r from-blue-600 to-green-400 text-white py-16 lg:py-24">
  <div class="container mx-auto px-4 text-center">
    <h2 class="text-3xl lg:text-4xl font-bold mb-4">¿Listo para impulsar tu negocio?</h2>
    <p class="text-lg lg:text-xl opacity-90 mb-8">Únete a cientos de empresas que ya confían en nosotros</p>
    <a routerLink="/el-futuro-es-ahora" class="bg-white text-blue-600 px-8 lg:px-10 py-3 lg:py-4 rounded-full font-semibold hover:-translate-y-1 hover:shadow-xl transition-all duration-300 inline-block text-lg">
      Comienza Ahora
    </a>
  </div>
</section>
